from typing import List

class Solution:
    def findMin(self, nums: List[int]) -> int:
        low, high = 0, len(nums)-1
        while low != high:
            mid = low + (high - low)//2
            if nums[mid] == nums[low]:
                return low if nums[mid] == nums[high] else self.findMin(nums[low:mid+1])
            elif nums[mid] > nums[low]:
                high = mid - 1
            else:
                low = mid + 1
        return low

